class Solution {
    public int[][] validArrangement(int[][] pairs) {
        int n = pairs.length;
        int[] indegree = new int[n];
        List<int[]>[] graph = new ArrayList[n];
        for (int i = 0; i < n; i++) {
            graph[i] = new ArrayList<>();
        }

        for (int i = 0; i < n; i++) {
            for (int j = 0; j < n; j++) {
                if (pairs[i][1] == pairs[j][0]) {
                    graph[i].add(pairs[j]);
                    indegree[j]++;
                }
            }
        }

        Queue<int[]> queue = new LinkedList<>();
        for (int i = 0; i < n; i++) {
            if (indegree[i] == 0) {
                queue.offer(pairs[i]);
            }
        }

        int[][] res = new int[n][2];
        int idx = 0;
        while (!queue.isEmpty()) {
            int[] cur = queue.poll();
            res[idx++] = cur;
            for (int[] next : graph[cur[0]]) {
                indegree[next[0]]--;
                if (indegree[next[0]] == 0) {
                    queue.offer(next);
                }
            }
        }

        return res;
    }
}
